    """Test basic dictionary zipping with multiple dicts."""
    dict1 = {"a": 1, "b": 2}
    dict2 = {"a": 3, "c": 4}
    dict3 = {"b": 5, "c": -1}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        "a": [1, 3, None],
        "b": [2, None, 5],
        "c": [None, 4, -1]
    }
    assert result == expected


